import React, { useState } from "react";
function JoiningDetails({ nextStep, updateData }) {
 const [data, setData] = useState({
   empId: "",
   firstName: "",
   lastName: "",
   designation: ""
 });
 const handleChange = (e) => {
   setData({ ...data, [e.target.name]: e.target.value });
 };
 const handleNext = () => {
   updateData(data);
   nextStep();
 };
 return (
<div>
<h2>Joining Details</h2>
<input name="empId" placeholder="Emp ID" onChange={handleChange} />
<input name="firstName" placeholder="First Name" onChange={handleChange} />
<input name="lastName" placeholder="Last Name" onChange={handleChange} />
<input name="designation" placeholder="Designation" onChange={handleChange} />
<button onClick={handleNext}>Next</button>
</div>
 );
}
export default JoiningDetails;